def submit_with_retry(queries: list[str], max_attempts: int = 3) -> dict:
    for attempt in range(max_attempts):
        try:
            path = create_batch_file(queries)
            batch_id = submit_batch(path)
            out_file_id = wait_for_batch(batch_id)
            return download_results(out_file_id)
        except RuntimeError as e:
            print(f"Attempt {attempt+1} failed: {e}")
            if attempt == max_attempts - 1:
                raise
            time.sleep(60)
    return {}
